const API_KEY = "5eb0e614";
const BASE_URL = "https://www.omdbapi.com/";

// Titles used to populate the "Trending" row on the home page.
// OMDb doesn't have a real trending/popular endpoint like TMDB, so instead
// I just picked some well known recent-ish movies.
export const TRENDING_TITLES = [
  "Dune: Part Two",
  "Oppenheimer",
  "Inside Out 2",
  "Deadpool & Wolverine",
  "The Batman",
  "Barbie",
  "Everything Everywhere All at Once",
];

// Titles used to populate the "Popular" row - classic / well known movies.
export const POPULAR_TITLES = [
  "The Dark Knight",
  "Inception",
  "Interstellar",
  "The Shawshank Redemption",
  "Pulp Fiction",
  "The Matrix",
  "Fight Club",
  "Forrest Gump",
];

/**
 * Search movies by title (used by the search bar).
 * OMDb's search endpoint only returns basic info (no plot/rating),
 * so this is used for search results grids, not the details page.
 */
export async function searchMovies(query) {
  const response = await fetch(
    `${BASE_URL}?apikey=${API_KEY}&s=${encodeURIComponent(query)}&type=movie`
  );
  const data = await response.json();

  // OMDb returns { Response: "False", Error: "..." } when nothing is found
  if (data.Response === "False") {
    return [];
  }

  return data.Search;
}

/**
 * Get one movie by its exact title.
 * Used for building the trending/popular rows from a hardcoded title list.
 */
export async function getMovieByTitle(title) {
  const response = await fetch(
    `${BASE_URL}?apikey=${API_KEY}&t=${encodeURIComponent(title)}`
  );
  const data = await response.json();

  if (data.Response === "False") {
    return null;
  }

  return data;
}

/**
 * Get full details for a movie by its IMDb ID (used on the Movie Details page).
 * plot=full gives the full plot instead of a short version.
 */
export async function getMovieById(imdbID) {
  const response = await fetch(
    `${BASE_URL}?apikey=${API_KEY}&i=${imdbID}&plot=full`
  );
  const data = await response.json();

  if (data.Response === "False") {
    return null;
  }

  return data;
}

/**
 * Fetches a list of movies by title in parallel.
 * Used to build the Trending/Popular sections from TRENDING_TITLES / POPULAR_TITLES.
 * Filters out any that failed to fetch (e.g. rate limit or typo).
 */
export async function getMoviesByTitles(titles) {
  const promises = titles.map((title) => getMovieByTitle(title));
  const results = await Promise.all(promises);
  return results.filter((movie) => movie !== null);
}
